import boto3
from botocore.exceptions import ClientError

def lambda_handler(event, context):
    # Example function that interacts with S3, DynamoDB, SNS, and SQS
    s3_client = boto3.client('s3')
    dynamodb_client = boto3.client('dynamodb')
    sns_client = boto3.client('sns')
    sqs_client = boto3.client('sqs')

    try:
        # Example operations
        s3_response = s3_client.list_buckets()
        print("S3 Buckets:", s3_response['Buckets'])

        dynamodb_response = dynamodb_client.scan(TableName='example_table')
        print("DynamoDB Items:", dynamodb_response.get('Items', []))

        sns_response = sns_client.publish(
            TopicArn='arn:aws:sns:region:account-id:topic-name',
            Message='Hello from Lambda!'
        )
        print("SNS Publish Response:", sns_response)

        sqs_response = sqs_client.send_message(
            QueueUrl='https://sqs.region.amazonaws.com/account-id/queue-name',
            MessageBody='Hello from Lambda!'
        )
        print("SQS Send Message Response:", sqs_response)

    except ClientError as e:
        print("Client error occurred:", e)

